	            if latitude == 0:
	                if d != "South":
	                    return "NO"
	            if latitude == 20000:
	                if d != "North":
	                    return "NO"
	            if d == "South":
	                latitude += l
	            elif d == "North":
	                latitude -= l
	            if not (0 <= latitude <= 20000):
	                return "NO"
	        if latitude != 0:
	            return "NO"
	        return "YES"

	    #################################################### HELPERS

	    def read(callback=int):
