	        hi=len(a)
	        lo=-1
	        while (lo+1<hi):
	            mi=(lo+hi)//2
	            if a[mi]==value:
	                return mi
	            if a[mi]<value:
	                lo=mi
	            else:
	                hi=mi
	        return -1


