	                    if a[k][1] <= j or j < a[k][0]:
	                        break
	                    if k == 0 or j != 0:
	                        tmp = cal(i - k + 1, g[j])
	                        if k > 0:
	                            f[i][j] += f[k - 1][j - 1] * tmp % M
	                        else:
	                            f[i][j] += tmp
	                        f[i][j] %= M

	    #print(f)
