	    def main():
	        try:
	            while True:
	                s, x1, x2 = list(map(int, input().split()))
	                t1, t2 = list(map(int, input().split()))
	                p, d = list(map(int, input().split()))

	                def travel(src, trg):
	                    nonlocal d
	                    if src == trg:
	                        return 0
	                    if src < trg:
	                        if d > 0:
	                            return trg - src
	                        else:
	                            d = 1
	                            return trg + src
	                    else:
	                        if d < 0:
	                            return src - trg
	                        else:
	                            d = -1
	                            return s - src + s - trg

	                a = travel(p, x1)
	                b = travel(x1, x2)
	                print("%d" % min(abs(x1 - x2) * t2, (a + b) * t1))

	        except EOFError:
	            pass

	    main()
	    ,,"assert walk_time == 8

