	        return sum(primeFactor(N).values()) == 1

	    def isPrimeMR(n):
	        # print("MR", n)
	        if n == 2: return True
	        if n == 1 or n & 1 == 0: return False

	        d = (n - 1) >> 1
	        while d & 1 == 0:
	            d >>= 1

	        for a in [2, 3, 5, 7, 11, 13, 17, 19]:
	            t = d
	            y = pow(a, t, n)

	            while t != n - 1 and y != 1 and y != n - 1:
	                y = (y * y) % n
	                t <<= 1

	            if y != n - 1 and t & 1 == 0:
	                # print("not prime")
	                return False
	        # print("prime")
	        return True

	    def findPrime(N):
	        if N < 0:
