	            x = heappop(frontier)
	            if x[0]!=dist[x[1]]:
	                continue
	            x = x[1]
	            for (i,l) in adj[x]:
	                if dist[x]+l<dist[i]:
	                    dist[i] = dist[x]+l
	                    ways[i] = ways[x]
	                    heappush(frontier,(dist[i],i))
