def call_solution():
	    MOD = 998244353

	    list_size = 1000001

	    f_list = [1] * list_size
	    f_r_list = [1] * list_size

	    for i in range(list_size - 1):
	        f_list[i + 1] = int((f_list[i] * (i + 2)) % MOD)

	    def power(n, x):
	        if x == 1:
	            return n
	        elif x % 2 == 0:
	            return power(int((n * n) % MOD), int(x / 2))
	        else:
	            return int((n * power(n, x - 1)) % MOD)

