	    def sqfree(x):
	        if x == 0:
	            return x
	        y = 1
	        for p, pp in zip(primes, psq):
	            while x % pp == 0:
	                x //= pp
	            if x % p == 0:
	                x //= p
	                y *= p
	            if abs(x) < p:
	                break
	        if int(sqrt(abs(x)))**2 == abs(x):
	            return (y if x > 0 else -y)
	        else:
	            return x * y

