	        while s <= n:
	            working = multiply(working,working,MOD)
	            s*= 2
	            pripravi[s] = copy(working)
	            pot.append(s)

	        manjka = n-2
	        pointer = len(pot) - 1
	        while manjka > 0:
	            if pot[pointer] > manjka:
	                pointer -= 1
	            else:
	                matrika = multiply(matrika, pripravi[pot[pointer]], MOD)
